import Layout from '../components/layout';
import {graphql} from 'gatsby';
import React from 'react';
import Box from '@mui/material/Box';
import Paper from '@mui/material/Paper';
import Grid from '@mui/material/Unstable_Grid2';
import Typography from '@mui/material/Typography';
import Divider from '@mui/material/Divider';
import Breadcrumbs from '@mui/material/Breadcrumbs';
import Link from '@mui/material/Link';
import Carousel from 'react-material-ui-carousel';

const NewsDetailsPage = ({data}) => {
  const newData = data.strapiCorporateNew;
  let html = newData.detail.data.childMarkdownRemark.html;

  if(newData.detail.medias&&newData.detail.medias.length){
    newData.detail.medias.forEach(item => {
      const reg = new RegExp(`(<img src="${item.src}".*?">)`, 'g');
      html=html.replaceAll(reg, `<div class="image-wrapper"><img src="${item.localFile.publicURL}"></div>`);

    });
  }

  return (
      <Layout>
        <Box sx={{mt: 2}}>
          <Paper sx={{mr: 2, ml: 2, pr: 1, pl: 1}} elevation={2}>
            <Breadcrumbs sx={{pt: 2, pl: 2, pr: 2}} aria-label="breadcrumb">
              <Link underline="hover" color="inherit" href="/">
                首页
              </Link>
              <Link
                  underline="hover"
                  color="inherit"
                  href="/news"
              >
                新闻资讯
              </Link>
              <Typography noWrap={true} sx={{width:{md:'300px',lg:'400px',xl:'600px',xs:'100px',sm:'200px'}}} color="text.primary">{newData.title}</Typography>
            </Breadcrumbs>
            <Grid container>
              <Grid item xs={12} md={12} display="flex" justifyContent="center">
                <Typography sx={{mt: 4, mb: 2}} variant="h4" component="div">
                  {newData.title}
                </Typography>
              </Grid>
              <Grid item xs={12} md={12} display="flex" justifyContent="center">
                <Typography sx={{ mb: 2}} variant="body2" component="div">
                  {newData.time}
                </Typography>
              </Grid>
            </Grid>
            <Divider/>
            <Grid sx={{mt: 2,width:'100%',height:'300px'}} container  spacing={2} display="flex"
                  justifyContent="center">

              <Carousel sx={{width:'100%'}}
                        animation="slide"
                        navButtonsAlwaysVisible={false}
                        navButtonsAlwaysInvisible={true}
                        indicators={true}>
                {newData?.media?.map((item, i) => {
                  return (
                      <Box >
                      <img loading="lazy" key={i}
                                style={{maxHeight:'100%',height:'240px',maxWidth:'100%',objectFit:'cover'}}
                               width="100%"  alt=""
                               src={item?.localFile.publicURL}/>
                      </Box>
                        );
                })}
              </Carousel>

            </Grid>
            <Grid className='markdown' sx={{overflowX: 'auto', ml: 1, mr: 1}}
                  dangerouslySetInnerHTML={{__html: html}}>

            </Grid>
          </Paper>


        </Box>

      </Layout>
  );
};

export const pageQuery = graphql`
  query ($id: String) {
    strapiCorporateNew(id: {eq: $id}) {
      desc
    detail {
      medias {
      src
        localFile {
         
          publicURL
        }
      }
      data {
        childMarkdownRemark {
          html
          
        }
      }
    }
    media {
      url
      localFile {
        publicURL
        childImageSharp {
          gatsbyImageData
        }
      }
    }
    title
    time
  }
  }
`;

export default NewsDetailsPage;
